import{_ as t,o as i,c as s,a2 as r}from"./chunks/framework.Cuq8tsM6.js";const v=JSON.parse('{"title":"Co-Branded Contest","description":"","frontmatter":{"title":"Co-Branded Contest"},"headers":[],"relativePath":"docs/fr/advertisers/co-branded-contest/index.md","filePath":"docs/fr/advertisers/co-branded-contest/index.md"}'),a={name:"docs/fr/advertisers/co-branded-contest/index.md"};function d(o,e,n,p,l,c){return i(),s("div",null,[...e[0]||(e[0]=[r('<h1 id="jeu-concours-co-brande" tabindex="-1">Jeu Concours Co-brandé <a class="header-anchor" href="#jeu-concours-co-brande" aria-label="Permalink to &quot;Jeu Concours Co-brandé&quot;">​</a></h1><p>Le dispositif puissant qui combine <strong>notoriété</strong> et <strong>acquisition de leads (Data)</strong>.</p><div class="mt-4 mb-6"><a href="workflow" class="btn btn-primary fs-4 mr-2">Voir le Process &amp; Data</a></div><hr class="mb-6"><h2 class="text-blue-200 mb-4">Pourquoi lancer un jeu concours ?</h2><div style="display:grid;grid-template-columns:repeat(auto-fit, minmax(280px, 1fr));gap:20px;width:100%;margin-bottom:40px;"><div style="border:1px solid var(--vp-c-divider);border-radius:8px;padding:24px;background:var(--vp-c-bg-elv);"><h3 class="mt-0 text-blue-200">📊 Acquisition de Leads (Opt-in)</h3><p class="fs-2 text-grey-dk-000 mb-2">Un e-commerçant partenaire héberge un jeu sur son site. En échange de la participation, l&#39;utilisateur accepte de recevoir vos offres.</p><div style="margin-top:10px;"><span style="background:var(--gi-tint-green-bg);border:1px solid var(--gi-tint-green-text);padding:4px 8px;border-radius:4px;font-size:12px;font-weight:bold;color:var(--gi-tint-green-text);">Objectif : Enrichir votre CRM</span></div></div><div style="border:1px solid var(--vp-c-divider);border-radius:8px;padding:24px;background:var(--vp-c-bg-elv);"><h3 class="mt-0 text-green-200">💰 Conversion Massive</h3><p class="fs-2 text-grey-dk-000 mb-0">Ne laissez aucun perdant ! Chaque participant reçoit un <strong>code promotionnel</strong> de &quot;consolation&quot; à la fin du jeu (ex: -15%). Cela transforme une mécanique gratuite en ventes immédiates.</p></div><div style="border:1px solid var(--vp-c-divider);border-radius:8px;padding:24px;background:var(--vp-c-bg-elv);"><h3 class="mt-0 text-purple-200">❤️ Engagement Fort</h3><p class="fs-2 text-grey-dk-000 mb-0">La mécanique de jeu (Gamification) crée un lien émotionnel positif. Vous bénéficiez de l&#39;image de marque du Distributeur qui &quot;offre&quot; ce jeu à sa communauté.</p></div></div><h2 class="text-grey-dk-000 mb-4">Votre Investissement</h2><div style="border:1px solid var(--vp-c-divider);border-radius:8px;padding:24px;background:var(--gi-tint-blue-bg);margin-bottom:40px;"><p class="fs-4 mt-0 mb-4">Outre le budget média, vous devez fournir :</p><div style="display:grid;grid-template-columns:repeat(auto-fit, minmax(200px, 1fr));gap:20px;"><div style="display:flex;align-items:start;gap:15px;"><div style="font-size:24px;">🏆</div><div><strong>La Dotation (Gros lots)</strong><br><span class="fs-2 text-grey-dk-000">Ce qui attire les joueurs (ex: 3 x 100€ de produits). Vous gérez l&#39;envoi aux gagnants.</span></div></div><div style="display:flex;align-items:start;gap:15px;"><div style="font-size:24px;">🎟️</div><div><strong>La Récompense (Consolation)</strong><br><span class="fs-2 text-grey-dk-000">Un code promo générique (ex: MERCI15) pour tous les participants.</span></div></div></div></div><h2 class="text-blue-200 mb-4">Pourquoi passer par getinside ?</h2><div style="display:flex;flex-direction:column;gap:20px;"><div style="border:1px solid var(--vp-c-divider);border-radius:8px;padding:24px;background:var(--vp-c-bg-elv);display:flex;align-items:center;gap:20px;"><div style="font-size:32px;min-width:50px;text-align:center;">⚡</div><div><h3 class="mt-0">Solution Clé en Main</h3><p class="fs-2 text-grey-dk-000 mb-0">Nous coordonnons la mise en place technique avec le distributeur (Landing Page, Flux). Vous n&#39;avez qu&#39;à fournir les lots et les visuels.</p></div></div><div style="border:1px solid var(--vp-c-divider);border-radius:8px;padding:24px;background:var(--vp-c-bg-elv);display:flex;align-items:center;gap:20px;"><div style="font-size:32px;min-width:50px;text-align:center;">⚖️</div><div><h3 class="mt-0">Conformité RGPD</h3><p class="fs-2 text-grey-dk-000 mb-0">La collecte de données est sensible. Nous nous assurons que le mécanisme d&#39;Opt-in (consentement) mis en place par l&#39;éditeur est parfaitement conforme pour que vous puissiez exploiter la base légalement.</p></div></div></div>',10)])])}const g=t(a,[["render",d]]);export{v as __pageData,g as default};
